+                }
+            }
+            
+            // Update row count
+            tbl.row_count += @as(u32, @intCast(inserted_count));
+            if (inserted_count > 0) {
+                log("DEBUG: Inserted rows successfully");
+            } else {
+                log("DEBUG: Inserted 0 rows");
+            }
+            return;
+        } else {
+            log("DEBUG: Source Table NOT FOUND");
+        }
+    }
+    tbl.row_count = new_count;
+}
